
.force-row {
  padding: 8px 9px;
  border: 1px solid rgba(148, 163, 184, 0.1);
  background: rgba(2, 6, 23, 0.25);
  transition:
    border-color 0.18s ease,
    background 0.18s ease;

  &:hover {
    border-color: rgba(59, 130, 246, 0.28);
    background: rgba(15, 23, 42, 0.55);
  }
}

.force-main,
.force-meta {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
}

.force-main {
  margin-bottom: 5px;
}

.force-name {
  min-width: 0;
  color: #e2e8f0;
  font-size: 13px;
  font-weight: 800;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.type-chip,
.armed,
.attitude {
  flex-shrink: 0;
  padding: 1px 5px;
  border-left: 2px solid;
  background: rgba(15, 23, 42, 0.68);
  font-size: 11px;
  font-weight: 800;
}

.armed {
  border-color: #f97316;
  color: #fed7aa;
}

.armed.pulse {
  color: #fecaca;
  border-color: #ef4444;
  animation: pulse-red 1.4s ease-in-out infinite;
}

.force-meta {
  color: #64748b;
  font-size: 12px;
}

.csat {
  border-color: #f97316;
  color: #fdba74;
}

.usa {
  border-color: #3b82f6;
  color: #93c5fd;
}

.support-track {
  height: 4px;
  margin-top: 6px;
  overflow: hidden;
  background: rgba(51, 65, 85, 0.7);

  span {
    display: block;
    height: 100%;
    background: linear-gradient(90deg, #ef4444, #f97316, #eab308, #22c55e);
    transition: width 0.3s ease;
  }
}

@keyframes pulse-red {
  0%,
  100% {
    opacity: 0.75;
  }
  50% {
    opacity: 1;
  }
}
