
.modal-mask {
  position: fixed;
  inset: 0;
  z-index: 9999;
  display: grid;
  place-items: center;
  padding: 10px;
  background: rgba(0, 0, 0, 0.54);
  backdrop-filter: blur(4px);
}

.settings-modal {
  width: min(460px, 94vw);
  max-height: 82vh;
  display: flex;
  flex-direction: column;
  border: 1px solid rgba(148, 163, 184, 0.2);
  border-radius: 8px;
  background: linear-gradient(180deg, rgba(15, 23, 42, 0.97), rgba(2, 6, 23, 0.99)), #0b1121;
  color: #cbd5e1;
  box-shadow: 0 18px 55px rgba(0, 0, 0, 0.55);
}

.modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 11px 14px;
  border-bottom: 1px solid rgba(148, 163, 184, 0.12);
  background: rgba(15, 23, 42, 0.96);
  flex-shrink: 0;

  button {
    width: 28px;
    height: 28px;
    border: 1px solid rgba(148, 163, 184, 0.18);
    background: rgba(2, 6, 23, 0.5);
    color: #94a3b8;
    font-size: 14px;
    cursor: pointer;
  }
}

.modal-title {
  color: #f8fafc;
  font-size: 15px;
  font-weight: 900;
}

.modal-body {
  flex: 1;
  overflow-y: auto;
  padding: 10px 14px;
}

.settings-section {
  margin-bottom: 14px;
  padding-bottom: 12px;
  border-bottom: 1px solid rgba(148, 163, 184, 0.08);

  h3 {
    margin: 0 0 8px;
    color: #e2e8f0;
    font-size: 13px;
    letter-spacing: 0.04em;
  }
}

// ── 阈值网格 ──
.threshold-grid {
  display: grid;
  gap: 6px;
}

.threshold-item {
  display: grid;
  grid-template-columns: 1fr auto 1fr;
  align-items: center;
  gap: 8px;
  padding: 2px 0;
  font-size: 12px;
}

.th-label {
  color: #94a3b8;
  font-weight: 800;
}

.th-control {
  display: flex;
  align-items: center;
  gap: 2px;

  button {
    width: 22px;
    height: 22px;
    border: 1px solid rgba(148, 163, 184, 0.2);
    background: rgba(2, 6, 23, 0.5);
    color: #94a3b8;
    font-size: 14px;
    cursor: pointer;
    line-height: 1;
  }

  input {
    width: 44px;
    padding: 2px 4px;
    border: 1px solid rgba(148, 163, 184, 0.2);
    background: rgba(2, 6, 23, 0.5);
    color: #e2e8f0;
    font-size: 12px;
    text-align: center;
  }
}

.th-hint {
  color: #64748b;
  font-size: 11px;
}

// ── 复选框组 ──
.checkbox-group {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 8px;
  margin-top: 8px;
  padding: 6px 8px;
  border: 1px solid rgba(148, 163, 184, 0.1);
  border-radius: 4px;
  background: rgba(2, 6, 23, 0.3);
}

.checkbox-label {
  color: #94a3b8;
  font-size: 12px;
  font-weight: 800;
  margin-right: 4px;
}

.checkbox-item {
  display: flex;
  align-items: center;
  gap: 3px;
  font-size: 11px;
  color: #cbd5e1;
  cursor: pointer;
}

// ── 内联控件 ──
.inline-controls {
  display: grid;
  gap: 8px;
}

.inline-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  font-size: 12px;
  color: #94a3b8;

  select,
  .small-input {
    padding: 3px 6px;
    border: 1px solid rgba(148, 163, 184, 0.2);
    background: rgba(2, 6, 23, 0.5);
    color: #e2e8f0;
    font-size: 11px;
    outline: none;
  }

  .small-input {
    width: 60px;
    text-align: center;
  }
}

// ── 颜色网格 ──
.color-grid {
  display: grid;
  gap: 5px;
}

.color-row {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 2px 0;
  font-size: 12px;
}

.color-swatch {
  width: 14px;
  height: 14px;
  border: 1px solid rgba(148, 163, 184, 0.3);
  border-radius: 3px;
  flex-shrink: 0;
}

.color-name {
  flex: 1;
  min-width: 0;
  color: #94a3b8;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.color-picker {
  width: 28px;
  height: 22px;
  border: none;
  background: transparent;
  cursor: pointer;
}

.color-hex {
  width: 58px;
  color: #64748b;
  font-size: 11px;
  font-family: monospace;
}

// ── 映射网格 ──
.map-grid {
  display: grid;
  gap: 4px;
}

.map-row {
  display: flex;
  align-items: center;
  gap: 5px;
  font-size: 12px;
}

.map-name {
  width: 80px;
  color: #94a3b8;
  font-weight: 800;
  flex-shrink: 0;
}

.map-input {
  flex: 1;
  padding: 3px 5px;
  border: 1px solid rgba(148, 163, 184, 0.18);
  background: rgba(2, 6, 23, 0.5);
  color: #e2e8f0;
  font-size: 11px;
  outline: none;
}

// ── 底部按钮 ──
.modal-footer {
  display: flex;
  justify-content: space-between;
  padding: 10px 14px;
  border-top: 1px solid rgba(148, 163, 184, 0.12);
  background: rgba(15, 23, 42, 0.96);
  flex-shrink: 0;
}

.btn-reset {
  padding: 6px 12px;
  border: 1px solid rgba(148, 163, 184, 0.2);
  background: rgba(2, 6, 23, 0.5);
  color: #94a3b8;
  font-size: 12px;
  font-weight: 800;
  cursor: pointer;

  &:hover {
    color: #e2e8f0;
  }
}

.btn-save {
  padding: 6px 16px;
  border: 1px solid #3b82f6;
  background: rgba(59, 130, 246, 0.18);
  color: #bfdbfe;
  font-size: 12px;
  font-weight: 800;
  cursor: pointer;

  &:hover {
    background: rgba(59, 130, 246, 0.28);
  }
}

@container main-panel (max-width: 430px) {
  .settings-modal {
    width: 95vw;
    max-height: 85vh;
  }
}
