
.panel-section {
  border: 1px solid rgba(148, 163, 184, 0.12);
  border-radius: 6px;
  background: rgba(15, 23, 42, 0.52);
}

.section-title {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 12px 8px;
  color: #e2e8f0;
  font-size: 14px;
  font-weight: 800;
  letter-spacing: 0.06em;
  border-bottom: 1px solid rgba(148, 163, 184, 0.1);
}

.standoff-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
  padding: 10px;
}

.side-card {
  padding: 9px;
  border: 1px solid rgba(148, 163, 184, 0.1);
  background: rgba(2, 6, 23, 0.32);
}

.side-title {
  margin-bottom: 7px;
  color: #cbd5e1;
  font-size: 13px;
  font-weight: 800;
}

:deep(.metric-row) {
  display: grid;
  grid-template-columns: 54px minmax(0, 1fr);
  gap: 4px 8px;
  align-items: center;
  margin: 5px 0;
  font-size: 12px;
}

:deep(.metric-label) {
  color: #64748b;
}

:deep(.metric-value) {
  min-width: 0;
  color: #e2e8f0;
  font-weight: 700;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

:deep(.mini-track) {
  grid-column: 1 / -1;
  height: 4px;
  overflow: hidden;
  background: rgba(51, 65, 85, 0.7);
}

:deep(.mini-fill) {
  display: block;
  height: 100%;
  transition: width 0.3s ease;
  background: #3b82f6;
}

:deep(.mini-fill.positive) {
  background: linear-gradient(90deg, #ef4444, #f97316, #eab308, #22c55e);
}

:deep(.mini-fill.negative) {
  background: linear-gradient(90deg, #22c55e, #eab308, #f97316, #ef4444);
}

.verdict {
  margin: 0 10px 10px;
  padding: 8px 10px;
  border-left: 3px solid #f97316;
  background: rgba(249, 115, 22, 0.1);
  color: #fed7aa;
  font-size: 13px;
  font-weight: 700;
  line-height: 1.5;
}

.fold-trigger {
  display: flex;
  justify-content: space-between;
  width: calc(100% - 20px);
  margin: 0 10px 8px;
  padding: 7px 9px;
  border: 1px solid rgba(148, 163, 184, 0.1);
  background: rgba(30, 41, 59, 0.38);
  color: #94a3b8;
  font-size: 12px;
  font-weight: 700;
  cursor: pointer;
}

.fold-body,
.decision-list {
  margin: 0 10px 10px;
  padding: 8px;
  border: 1px solid rgba(148, 163, 184, 0.08);
  background: rgba(2, 6, 23, 0.25);
}

:deep(.info-line) {
  display: grid;
  grid-template-columns: 100px minmax(0, 1fr);
  gap: 8px;
  padding: 4px 0;
  font-size: 12px;
}

:deep(.info-label) {
  color: #64748b;
}

:deep(.info-value) {
  color: #cbd5e1;
}

.decision-item {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  padding: 5px 0;
  font-size: 12px;
  border-bottom: 1px solid rgba(148, 163, 184, 0.06);

  &:last-child {
    border-bottom: none;
  }
}

.decision-text {
  color: #cbd5e1;
}

.status-chip {
  flex-shrink: 0;
  padding: 1px 5px;
  border-left: 2px solid;
  background: rgba(15, 23, 42, 0.65);
  font-weight: 800;
}

.empty-box,
.empty-mini {
  padding: 12px;
  color: #64748b;
  font-size: 13px;
  text-align: center;
}

.fold-enter-active,
.fold-leave-active {
  transition: all 0.18s ease;
}

.fold-enter-from,
.fold-leave-to {
  opacity: 0;
  transform: translateY(-3px);
}

@container main-panel (max-width: 430px) {
  .standoff-grid {
    grid-template-columns: 1fr;
  }

  :deep(.info-line) {
    grid-template-columns: 82px minmax(0, 1fr);
  }
}
