
.modal-mask {
  position: fixed;
  inset: 0;
  z-index: 9999;
  display: grid;
  place-items: center;
  padding: 12px;
  background: rgba(0, 0, 0, 0.54);
  backdrop-filter: blur(4px);
}

.minister-modal {
  width: min(380px, 92vw);
  max-height: 75vh;
  overflow-y: auto;
  border: 1px solid rgba(148, 163, 184, 0.2);
  border-radius: 8px;
  background: linear-gradient(180deg, rgba(15, 23, 42, 0.96), rgba(2, 6, 23, 0.98)), #0b1121;
  color: #cbd5e1;
  box-shadow: 0 18px 55px rgba(0, 0, 0, 0.55);
}

.modal-header {
  position: sticky;
  top: 0;
  z-index: 1;
  display: flex;
  justify-content: space-between;
  gap: 12px;
  padding: 12px 13px 10px;
  border-bottom: 1px solid rgba(148, 163, 184, 0.12);
  background: rgba(15, 23, 42, 0.96);

  button {
    width: 28px;
    height: 28px;
    border: 1px solid rgba(148, 163, 184, 0.18);
    background: rgba(2, 6, 23, 0.5);
    color: #94a3b8;
    cursor: pointer;
  }
}

.modal-title {
  color: #f8fafc;
  font-size: 15px;
  font-weight: 900;
}

.modal-alert {
  margin-top: 4px;
  color: #fbbf24;
  font-size: 12px;
  font-weight: 800;

  &.dead {
    color: #f87171;
  }
}

.detail-section {
  padding: 11px 13px;
  border-bottom: 1px solid rgba(148, 163, 184, 0.08);

  h3 {
    margin: 0 0 9px;
    color: #e2e8f0;
    font-size: 14px;
    letter-spacing: 0.04em;
  }
}

.name-line {
  display: flex;
  align-items: baseline;
  gap: 5px;
  color: #f8fafc;

  strong {
    font-size: 18px;
  }
}

.subtext {
  margin-top: 4px;
  color: #64748b;
  font-size: 12px;
}

.tag-line,
.safety-line {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 9px;
  font-size: 12px;
}

.stance {
  padding: 2px 6px;
  border-left: 3px solid;
  background: rgba(15, 23, 42, 0.7);
  font-weight: 800;
}

:deep(.info-line) {
  display: grid;
  grid-template-columns: 82px minmax(0, 1fr);
  gap: 8px;
  padding: 4px 0;
  font-size: 12px;
}

:deep(.info-label) {
  color: #64748b;
}

:deep(.info-value) {
  color: #cbd5e1;
  line-height: 1.45;
}

:deep(.info-note) {
  grid-column: 2;
  color: #64748b;
  line-height: 1.45;
}

:deep(.progress-wrap) {
  display: flex;
  align-items: center;
  gap: 7px;
}

:deep(.progress-track) {
  flex: 1;
  min-width: 82px;
  height: 5px;
  overflow: hidden;
  background: rgba(51, 65, 85, 0.75);
}

:deep(.progress-fill) {
  display: block;
  height: 100%;
  transition: width 0.3s ease;
}

:deep(.progress-fill.positive) {
  background: linear-gradient(90deg, #ef4444, #f97316, #eab308, #22c55e);
}

:deep(.progress-fill.negative) {
  background: linear-gradient(90deg, #22c55e, #eab308, #f97316, #ef4444);
}

:deep(.progress-num) {
  color: #e2e8f0;
}

@container main-panel (max-width: 430px) {
  .minister-modal {
    width: 95vw;
    max-height: 75vh;
  }
}
