
.ministry-row {
  padding: 9px 10px;
  border: 1px solid rgba(148, 163, 184, 0.1);
  border-left: 2px solid #22c55e;
  background: rgba(2, 6, 23, 0.25);
  transition:
    border-color 0.2s ease,
    background 0.2s ease;

  &:hover {
    border-color: rgba(59, 130, 246, 0.28);
    background: rgba(15, 23, 42, 0.55);
  }

  &.status-paralyzed {
    background: rgba(234, 179, 8, 0.04);
  }

  &.status-halted {
    background: rgba(239, 68, 68, 0.05);
  }
}

.row-top {
  display: flex;
  align-items: center;
  gap: 5px;
  margin-bottom: 6px;
}

.criticality-icon {
  font-size: 12px;
}

.criticality-label {
  font-size: 11px;
  font-weight: 800;
}

.ministry-name {
  flex: 1;
  min-width: 0;
  color: #f8fafc;
  font-size: 14px;
  font-weight: 900;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.status-chip {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 2px 7px;
  border-left: 2px solid;
  background: rgba(2, 6, 23, 0.45);
  font-size: 11px;
  font-weight: 800;
}

.status-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
}

// ── 掌控度对抗条（单条双端填充） ──
.control-bar-row {
  display: grid;
  grid-template-columns: 42px minmax(0, 1fr) 52px;
  align-items: center;
  gap: 5px;
  margin-bottom: 4px;
}

.control-label {
  font-size: 10px;
  font-weight: 900;
  white-space: nowrap;
}

.cabinet-label {
  color: #94a3b8;
  text-align: right;
}

.bureau-label {
  color: #94a3b8;
  text-align: left;
}

// 单条双端轨道
.control-dual-track {
  position: relative;
  height: 18px;
  overflow: hidden;
  background: rgba(30, 41, 59, 0.9);
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: 2px;
}

.control-fill-l {
  position: absolute;
  top: 0;
  left: 0;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: flex-end;
  padding-right: 3px;
  background: #3b82f6;
  transition: width 0.35s ease;
  z-index: 1;
}

// 蓝色截止标记（内阁侧右端）
.control-stopper-l {
  position: absolute;
  top: 0;
  right: 0;
  width: 3px;
  height: 100%;
  background: #60a5fa;
  box-shadow: 0 0 4px rgba(59, 130, 246, 0.6);
  border-radius: 0 1px 1px 0;
}

.control-fill-r {
  position: absolute;
  top: 0;
  right: 0;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: flex-start;
  padding-left: 3px;
  background: #ef4444;
  transition: width 0.35s ease;
  z-index: 1;
}

// 红色截止标记（事务次官侧左端）
.control-stopper-r {
  position: absolute;
  top: 0;
  left: 0;
  width: 3px;
  height: 100%;
  background: #f87171;
  box-shadow: 0 0 4px rgba(239, 68, 68, 0.6);
  border-radius: 1px 0 0 1px;
}

.control-fill-label {
  font-size: 9px;
  font-weight: 900;
  color: #fff;
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.7);
  white-space: nowrap;
}

// 对抗中线
.control-divider {
  position: absolute;
  top: 0;
  left: 50%;
  width: 1px;
  height: 100%;
  background: rgba(255, 255, 255, 0.2);
  z-index: 0;
  pointer-events: none;
}

.control-label {
  white-space: nowrap;
  font-weight: 800;
}

.cabinet-label {
  color: #94a3b8;
}

.bureau-label {
  color: #94a3b8;
}

// ── 折叠区域 ──
.row-details {
  overflow: hidden;
}

// ── 派系 + 态度 ──
.faction-attitude-row {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
  padding: 5px 0;
  font-size: 12px;
}

.faction-label {
  padding: 2px 6px;
  border-left: 3px solid;
  background: rgba(15, 23, 42, 0.7);
  font-weight: 800;
  cursor: pointer;
}

.attitude-block {
  display: inline-flex;
  align-items: center;
  gap: 3px;
  font-size: 11px;
}

.attitude-label {
  color: #64748b;
  font-weight: 800;
}

.attitude-swatch {
  width: 10px;
  height: 10px;
  border-radius: 2px;
}

.attitude-value {
  font-weight: 800;
}

// ── 焦点 ──
.focus-row {
  display: flex;
  align-items: flex-start;
  gap: 4px;
  padding: 4px 0;
  font-size: 12px;
  line-height: 1.45;
}

.focus-label {
  flex-shrink: 0;
  color: #64748b;
  font-weight: 800;
}

.focus-text {
  color: #cbd5e1;

  &.truncated {
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }
}

.focus-empty {
  color: #64748b;
  font-style: italic;
}

// ── 阁僚 + 政策 ──
.meta-row {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 12px;
  padding: 4px 0;
  font-size: 12px;
  color: #94a3b8;
}

.meta-item {
  display: inline-flex;
  align-items: center;
  gap: 3px;
}

.minister-link {
  padding-left: 5px;
  border-left: 2px solid;
  color: #e2e8f0;
  font-weight: 800;
  cursor: pointer;

  &:hover {
    color: #60a5fa;
  }
}

.policy-link {
  color: #60a5fa;
  font-weight: 800;
  cursor: pointer;

  &:hover {
    text-decoration: underline;
  }
}

.meta-empty {
  color: #64748b;
}

// ── 副大臣 + 事务次官 ──
.personnel-row {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 12px;
  padding: 4px 0;
  font-size: 12px;
  color: #94a3b8;
}

.personnel-name {
  font-weight: 800;
}

.personnel-sub {
  color: #64748b;
  font-size: 11px;
}

// ── 下属局厅 ──
.bureau-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 4px 0;
  font-size: 12px;
  color: #94a3b8;
}

.bureau-summary {
  font-weight: 800;
}

// ── 详情入口 ──
.detail-entry {
  padding: 4px 0;
}

.detail-btn {
  border: none;
  background: transparent;
  color: #60a5fa;
  font-size: 12px;
  font-weight: 800;
  cursor: pointer;

  &:hover {
    color: #93c5fd;
  }
}

// ── 预警标签 ──
.warning-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  padding-top: 5px;
}

.warning-tag {
  padding: 1px 6px;
  border-radius: 3px;
  background: rgba(2, 6, 23, 0.5);
  font-size: 11px;
  font-weight: 800;
}

.warning-pulse-red {
  animation: pulse-red 1.5s ease-in-out infinite;
}

.warning-pulse-blue {
  animation: pulse-blue 1.5s ease-in-out infinite;
}

@keyframes pulse-red {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.6;
  }
}

@keyframes pulse-blue {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.6;
  }
}

// ── 折叠/展开按钮 ──
.expand-btn,
.collapse-toggle {
  border: none;
  background: transparent;
  color: #60a5fa;
  font-size: 11px;
  font-weight: 800;
  cursor: pointer;

  &:hover {
    color: #93c5fd;
  }
}

.collapse-toggle {
  display: block;
  width: 100%;
  padding: 4px 0 0;
  text-align: center;
}

// ── 折叠过渡 ──
.fold-enter-active,
.fold-leave-active {
  transition:
    max-height 0.3s ease,
    opacity 0.25s ease;
  overflow: hidden;
}

.fold-enter-from,
.fold-leave-to {
  max-height: 0;
  opacity: 0;
}

.fold-enter-to,
.fold-leave-from {
  max-height: 500px;
  opacity: 1;
}

// ── 移动端 ──
@container main-panel (max-width: 430px) {
  .ministry-name {
    font-size: 12px;
  }

  .control-bar-row {
    font-size: 10px;
  }

  .faction-attitude-row {
    font-size: 11px;
  }

  .focus-row {
    font-size: 11px;
  }

  .attitude-swatch {
    width: 8px;
    height: 8px;
  }
}
