
.cabinet-panel {
  display: grid;
  gap: 10px;
}

.cabinet-header {
  display: flex;
  align-items: end;
  justify-content: space-between;
  gap: 12px;
  padding: 10px 12px;
  border: 1px solid rgba(148, 163, 184, 0.12);
  background: rgba(15, 23, 42, 0.48);

  h2 {
    margin: 2px 0 0;
    color: #f8fafc;
    font-size: 17px;
    letter-spacing: 0.08em;
  }
}

.eyebrow {
  color: #64748b;
  font-size: 11px;
  font-weight: 900;
  letter-spacing: 0.16em;
}

.panel-section {
  border: 1px solid rgba(148, 163, 184, 0.12);
  border-radius: 6px;
  background: rgba(15, 23, 42, 0.52);
}

.section-title {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 12px 8px;
  color: #e2e8f0;
  font-size: 14px;
  font-weight: 800;
  letter-spacing: 0.06em;
  border-bottom: 1px solid rgba(148, 163, 184, 0.1);
}

.overview-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 8px;
  padding: 10px;
}

:deep(.info-tile) {
  min-width: 0;
  padding: 8px;
  border-left: 3px solid rgba(59, 130, 246, 0.75);
  background: rgba(2, 6, 23, 0.28);
}

:deep(.tile-label) {
  display: block;
  margin-bottom: 4px;
  color: #64748b;
  font-size: 11px;
  font-weight: 900;
}

:deep(.tile-value) {
  display: block;
  color: #e2e8f0;
  font-size: 13px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.stability-line {
  display: grid;
  grid-template-columns: 70px minmax(0, 1fr) 50px;
  align-items: center;
  gap: 8px;
  padding: 0 10px 11px;
  color: #94a3b8;
  font-size: 12px;
}

.stability-track {
  height: 7px;
  overflow: hidden;
  background: rgba(51, 65, 85, 0.7);

  span {
    display: block;
    height: 100%;
    transition: width 0.3s ease;
  }
}

.status-stamp,
.count-chip,
.coalition-chip {
  flex-shrink: 0;
  padding: 2px 7px;
  border-left: 2px solid;
  background: rgba(2, 6, 23, 0.45);
  font-size: 12px;
  font-weight: 900;
}

.coalition-line {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 6px;
  padding: 10px 10px 0;
  font-size: 12px;
}

.muted,
.empty-inline {
  color: #64748b;
}

.coalition-chip {
  border-color: #3b82f6;
  color: #bfdbfe;
}

.force-list,
.minister-list,
.policy-list {
  display: grid;
  gap: 6px;
  padding: 10px;
}

.empty-box,
.policy-empty {
  padding: 14px 10px;
  color: #64748b;
  font-size: 13px;
  text-align: center;
}

.policy-empty button,
.policy-link {
  margin-left: 6px;
  border: none;
  background: transparent;
  color: #60a5fa;
  font-size: 13px;
  font-weight: 800;
  cursor: pointer;
}

.policy-count {
  color: #94a3b8;
  font-size: 12px;
}

.policy-item {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto auto;
  gap: 8px;
  align-items: center;
  padding: 7px 8px;
  border: 1px solid rgba(148, 163, 184, 0.08);
  background: rgba(2, 6, 23, 0.25);
  font-size: 12px;
}

.policy-name {
  min-width: 0;
  color: #e2e8f0;
  font-weight: 800;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.effect {
  color: #94a3b8;
}

.skeleton-cabinet {
  display: grid;
  gap: 10px;
}

.skeleton-block {
  height: 32px;
  border-radius: 4px;
  background: linear-gradient(90deg, #1e293b, #334155, #1e293b);
  background-size: 200% 100%;
  animation: shimmer 1.4s ease-in-out infinite;
}

.w60 {
  width: 60%;
}
.h60 {
  height: 60px;
}
.h84 {
  height: 84px;
}
.h120 {
  height: 120px;
}

@keyframes shimmer {
  0% {
    background-position: 100% 0;
  }
  100% {
    background-position: -100% 0;
  }
}

@container main-panel (max-width: 430px) {
  .overview-grid {
    grid-template-columns: 1fr 1fr;
  }

  .cabinet-header {
    align-items: center;
  }

  .policy-item {
    grid-template-columns: 1fr;
    gap: 5px;
  }
}
