
.ministry-panel {
  display: grid;
  gap: 10px;
}

// ── 总览条 ──
.overview-bar {
  padding: 10px 12px;
  border: 1px solid rgba(148, 163, 184, 0.12);
  background: rgba(15, 23, 42, 0.48);
}

.overview-title {
  margin-bottom: 8px;
}

.title-row {
  display: flex;
  align-items: center;
  justify-content: space-between;

  h2 {
    margin: 2px 0 0;
    color: #f8fafc;
    font-size: 17px;
    letter-spacing: 0.08em;
  }
}

.settings-btn {
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: 4px;
  background: rgba(2, 6, 23, 0.4);
  color: #94a3b8;
  font-size: 14px;
  cursor: pointer;
  transition: all 0.15s ease;

  &:hover {
    border-color: rgba(59, 130, 246, 0.4);
    color: #e2e8f0;
    background: rgba(59, 130, 246, 0.1);
  }
}

.eyebrow {
  color: #64748b;
  font-size: 11px;
  font-weight: 900;
  letter-spacing: 0.16em;
}

.overview-stats {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 6px;
  font-size: 12px;
  color: #94a3b8;
}

.stat-dot {
  display: inline-block;
  width: 6px;
  height: 6px;
  border-radius: 50%;

  &.green {
    background: #22c55e;
  }
  &.yellow {
    background: #eab308;
  }
  &.red {
    background: #ef4444;
  }
}

.overview-control {
  display: flex;
  gap: 16px;
  font-size: 12px;
  color: #94a3b8;

  strong {
    color: #e2e8f0;
  }
}

.overview-verdict {
  margin-top: 6px;
  padding: 4px 8px;
  border-radius: 4px;
  background: rgba(2, 6, 23, 0.4);
  font-size: 12px;
  font-weight: 800;

  &.verdict-critical {
    color: #ef4444;
    border-left: 3px solid #ef4444;
  }

  &.verdict-warning {
    color: #eab308;
    border-left: 3px solid #eab308;
  }

  &.verdict-ok {
    color: #22c55e;
    border-left: 3px solid #22c55e;
  }
}

// ── 搜索框 ──
.search-bar {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 10px;
  border: 1px solid rgba(148, 163, 184, 0.12);
  border-radius: 6px;
  background: rgba(15, 23, 42, 0.52);
}

.search-icon {
  font-size: 13px;
}

.search-input {
  flex: 1;
  border: none;
  background: transparent;
  color: #e2e8f0;
  font-size: 12px;
  outline: none;

  &::placeholder {
    color: #64748b;
  }
}

.search-clear {
  border: none;
  background: transparent;
  color: #64748b;
  font-size: 12px;
  cursor: pointer;

  &:hover {
    color: #94a3b8;
  }
}

// ── 筛选栏 ──
.filter-bar {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
  padding: 6px 0;
  font-size: 12px;
}

.filter-group {
  display: flex;
  align-items: center;
  gap: 4px;
}

.filter-label {
  color: #64748b;
  font-weight: 800;
}

.filter-btn {
  padding: 2px 8px;
  border: 1px solid rgba(148, 163, 184, 0.15);
  border-radius: 3px;
  background: rgba(2, 6, 23, 0.3);
  color: #94a3b8;
  font-size: 11px;
  font-weight: 800;
  cursor: pointer;
  transition: all 0.15s ease;

  &:hover {
    border-color: rgba(59, 130, 246, 0.3);
    color: #e2e8f0;
  }

  &.active {
    border-color: #3b82f6;
    background: rgba(59, 130, 246, 0.12);
    color: #bfdbfe;
  }
}

.sort-group {
  display: flex;
  align-items: center;
  gap: 4px;
  margin-left: auto;
}

.sort-select {
  padding: 2px 6px;
  border: 1px solid rgba(148, 163, 184, 0.15);
  border-radius: 3px;
  background: rgba(2, 6, 23, 0.5);
  color: #e2e8f0;
  font-size: 11px;
  outline: none;
  cursor: pointer;
}

// ── 省厅列表 ──
.panel-section {
  border: 1px solid rgba(148, 163, 184, 0.12);
  border-radius: 6px;
  background: rgba(15, 23, 42, 0.52);
}

.ministry-list {
  padding: 10px;
}

.ministry-entries {
  display: grid;
  gap: 6px;
}

.ministry-entry {
  border-radius: 4px;
}

.empty-box {
  padding: 14px 10px;
  color: #64748b;
  font-size: 13px;
  text-align: center;
}

// ── 低频省厅折叠区 ──
.low-priority-section {
  padding: 0;
}

.fold-trigger {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  padding: 10px 12px;
  border: none;
  background: transparent;
  color: #e2e8f0;
  font-size: 13px;
  font-weight: 800;
  cursor: pointer;

  span:last-child {
    color: #60a5fa;
    font-size: 12px;
  }
}

.low-priority-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  padding: 0 12px 10px;
}

.low-tag {
  padding: 2px 6px;
  border-radius: 3px;
  background: rgba(2, 6, 23, 0.4);
  color: #64748b;
  font-size: 12px;
  cursor: pointer;
  transition: color 0.15s ease;

  &:hover {
    color: #e2e8f0;
  }

  &.tag-yellow {
    color: #eab308;
  }

  &.tag-red {
    color: #ef4444;
  }
}

.low-warning {
  font-size: 10px;
}

// ── 骨架屏 ──
.skeleton-ministry {
  display: grid;
  gap: 10px;
}

.skeleton-block {
  height: 32px;
  border-radius: 4px;
  background: linear-gradient(90deg, #1e293b, #334155, #1e293b);
  background-size: 200% 100%;
  animation: shimmer 1.4s ease-in-out infinite;
}

.w60 {
  width: 60%;
}
.h40 {
  height: 40px;
}
.h80 {
  height: 80px;
}
.h120 {
  height: 120px;
}

@keyframes shimmer {
  0% {
    background-position: 100% 0;
  }
  100% {
    background-position: -100% 0;
  }
}

// ── 折叠过渡 ──
.fold-enter-active,
.fold-leave-active {
  transition:
    max-height 0.3s ease,
    opacity 0.25s ease;
  overflow: hidden;
}

.fold-enter-from,
.fold-leave-to {
  max-height: 0;
  opacity: 0;
}

.fold-enter-to,
.fold-leave-from {
  max-height: 800px;
  opacity: 1;
}

// ── 移动端 ──
@container main-panel (max-width: 430px) {
  .filter-bar {
    overflow-x: auto;
    scrollbar-width: none;

    &::-webkit-scrollbar {
      display: none;
    }
  }

  .filter-btn,
  .sort-select {
    min-height: 36px;
  }

  .overview-control {
    flex-direction: column;
    gap: 4px;
  }
}
