.minister-row{display:grid;grid-template-columns:24px 24px minmax(70px, 1.05fr) minmax(70px, 0.95fr) 20px minmax(68px, 0.75fr) minmax(68px, 0.75fr) 20px 16px;align-items:center;gap:5px;width:100%;padding:7px 8px;border:1px solid rgba(148,163,184,.1);background:rgba(2,6,23,.2);color:#cbd5e1;font-size:12px;text-align:left;cursor:pointer;transition:all .2s ease}.minister-row:hover:not(:disabled){border-color:rgba(59,130,246,.32);background:rgba(15,23,42,.62)}.minister-row:disabled{cursor:not-allowed}.threat-icon,.position-icon,.life-mark,.arrow,.control-mark{text-align:center;font-weight:900}.position-name,.minister-name{min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.position-name{color:#94a3b8;font-weight:800}.minister-name{padding-left:6px;border-left:2px solid #64748b;color:#f8fafc;font-weight:900}.status-chip{min-width:0;padding:2px 5px;border-left:2px solid;background:rgba(15,23,42,.68);font-weight:800;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.arrow{color:#64748b}.threatened .minister-name::after{content:" ⚠";color:#eab308}.attacked{background:rgba(249,115,22,.1)}.dead{opacity:.48;filter:grayscale(0.7)}.dead .minister-name,.dead .position-name{text-decoration:line-through}.exiled{opacity:.62;font-style:italic}@container main-panel (max-width: 430px){.minister-row{grid-template-columns:20px 20px minmax(64px, 1fr) minmax(68px, 1fr) 18px 18px;gap:4px}.status-chip{grid-row:2;font-size:11px}.understand{grid-column:3/4}.duty{grid-column:4/5}.life-mark{grid-column:5/6}.arrow{grid-column:6/7}}