
.modal-mask {
  position: fixed;
  inset: 0;
  z-index: 9999;
  display: grid;
  place-items: center;
  padding: 12px;
  background: rgba(0, 0, 0, 0.54);
  backdrop-filter: blur(4px);
}

.ministry-modal {
  width: min(420px, 92vw);
  max-height: 75vh;
  overflow-y: auto;
  border: 1px solid rgba(148, 163, 184, 0.2);
  border-radius: 8px;
  background: linear-gradient(180deg, rgba(15, 23, 42, 0.96), rgba(2, 6, 23, 0.98)), #0b1121;
  color: #cbd5e1;
  box-shadow: 0 18px 55px rgba(0, 0, 0, 0.55);
}

.modal-header {
  position: sticky;
  top: 0;
  z-index: 1;
  display: flex;
  justify-content: space-between;
  gap: 12px;
  padding: 12px 13px 10px;
  border-bottom: 1px solid rgba(148, 163, 184, 0.12);
  background: rgba(15, 23, 42, 0.96);
}

.header-actions {
  display: flex;
  align-items: center;
  gap: 6px;
}

.header-actions button {
  height: 28px;
  padding: 0 8px;
  border: 1px solid rgba(148, 163, 184, 0.18);
  background: rgba(2, 6, 23, 0.5);
  color: #94a3b8;
  font-size: 12px;
  font-weight: 800;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease;
}

.edit-btn:hover {
  border-color: #3b82f6;
  color: #60a5fa;
}

.save-btn {
  border-color: rgba(34, 197, 94, 0.35) !important;
  color: #22c55e !important;
}

.save-btn:hover {
  border-color: #22c55e !important;
  background: rgba(34, 197, 94, 0.08) !important;
}

.cancel-btn:hover {
  border-color: #eab308;
  color: #eab308;
}

.close-btn:hover {
  border-color: #ef4444;
  color: #ef4444;
}

.modal-title {
  color: #f8fafc;
  font-size: 15px;
  font-weight: 900;
}

.detail-section {
  padding: 11px 13px;
  border-bottom: 1px solid rgba(148, 163, 184, 0.08);

  h3 {
    margin: 0 0 9px;
    color: #e2e8f0;
    font-size: 14px;
    letter-spacing: 0.04em;
  }
}

.info-row {
  display: flex;
  gap: 16px;
  font-size: 13px;
}

// ── 进度条 ──
.bar-row {
  display: grid;
  grid-template-columns: 90px minmax(0, 1fr) 42px;
  align-items: center;
  gap: 8px;
  padding: 4px 0;
  font-size: 12px;
}

.bar-label {
  color: #64748b;
  font-weight: 800;
}

.bar-track {
  height: 6px;
  overflow: hidden;
  background: rgba(51, 65, 85, 0.75);

  &.attitude-track {
    position: relative;
  }
}

.bar-fill {
  display: block;
  height: 100%;
  transition: width 0.3s ease;
}

.bar-center-line {
  position: absolute;
  top: 0;
  left: 50%;
  width: 1px;
  height: 100%;
  background: rgba(148, 163, 184, 0.3);
}

.attitude-fill {
  position: absolute;
  top: 0;
  height: 100%;
}

.bar-num {
  color: #e2e8f0;
  font-size: 12px;
}

.control-diff {
  display: flex;
  align-items: center;
  gap: 8px;
  padding-top: 4px;
  font-size: 12px;
  color: #94a3b8;
}

.diff-warning {
  color: #f97316;
  font-weight: 800;
}

// ── 派系标签 ──
.faction-tag {
  display: inline-block;
  padding: 3px 8px;
  border-left: 3px solid;
  background: rgba(15, 23, 42, 0.7);
  font-size: 13px;
  font-weight: 800;
}

// ── 政策列表 ──
.policy-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 5px 0;
  font-size: 12px;
}

.policy-name {
  flex: 1;
  min-width: 0;
  color: #e2e8f0;
  font-weight: 800;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.status-chip {
  flex-shrink: 0;
  padding: 1px 5px;
  border-left: 2px solid;
  background: rgba(2, 6, 23, 0.45);
  font-size: 11px;
  font-weight: 800;
}

// ── 阁僚 ──
.minister-info {
  display: flex;
  align-items: baseline;
  gap: 8px;
  margin-bottom: 6px;
}

.minister-position {
  color: #64748b;
  font-size: 12px;
}

.minister-name {
  padding-left: 5px;
  border-left: 2px solid;
  color: #f8fafc;
  font-size: 15px;
}

.minister-details {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  margin-bottom: 6px;
  font-size: 12px;
  color: #94a3b8;
}

// ── 人事三巨头通用 ──
.personnel-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
}

.personnel-name {
  color: #f8fafc;
  font-size: 15px;
}

.personnel-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 4px 12px;
  font-size: 12px;
  color: #94a3b8;

  strong {
    color: #cbd5e1;
  }
}

.personnel-edit {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.form-sep {
  color: #475569;
  margin: 0 4px;
}

// ── 下属机构 ──
.bureau-grid {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
}

.bureau-chip {
  padding: 2px 6px;
  border-radius: 3px;
  background: rgba(2, 6, 23, 0.4);
  font-size: 11px;
}

.active-chip {
  color: #cbd5e1;
  font-weight: 800;
}

.dormant-chip {
  color: #64748b;
}

// ── 下属机构编辑模式 ──
.bureau-edit-list {
  display: flex;
  flex-direction: column;
  gap: 2px;
  max-height: 240px;
  overflow-y: auto;
}

.bureau-edit-hint {
  margin-bottom: 6px;
  color: #64748b;
  font-size: 11px;
  font-style: italic;
}

.bureau-check-row {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 3px 4px;
  border-radius: 3px;
  font-size: 12px;
  cursor: pointer;
  transition: background 0.12s ease;

  &:hover {
    background: rgba(59, 130, 246, 0.08);
  }

  &.active .bureau-check-name {
    color: #e2e8f0;
    font-weight: 800;
  }

  input[type='checkbox'] {
    accent-color: #3b82f6;
    cursor: pointer;
  }
}

.bureau-check-name {
  flex: 1;
  min-width: 0;
  color: #64748b;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.bureau-check-status {
  flex-shrink: 0;
  font-size: 10px;

  .bureau-check-row.active & {
    color: #22c55e;
    font-weight: 800;
  }

  .bureau-check-row:not(.active) & {
    color: #64748b;
  }
}

.bureau-add-row {
  display: flex;
  gap: 6px;
  margin-top: 8px;
  padding-top: 6px;
  border-top: 1px solid rgba(148, 163, 184, 0.08);
}

.bureau-add-input {
  flex: 1;
}

.bureau-add-btn {
  flex-shrink: 0;
  padding: 4px 10px;
  border: 1px solid rgba(59, 130, 246, 0.3);
  border-radius: 3px;
  background: rgba(59, 130, 246, 0.08);
  color: #60a5fa;
  font-size: 12px;
  font-weight: 800;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    background 0.15s ease;

  &:hover:not(:disabled) {
    border-color: #3b82f6;
    background: rgba(59, 130, 246, 0.16);
  }

  &:disabled {
    border-color: rgba(148, 163, 184, 0.1);
    background: transparent;
    color: #475569;
    cursor: not-allowed;
  }
}

// ── 焦点 ──
.focus-full {
  color: #cbd5e1;
  font-size: 13px;
  line-height: 1.5;
}

.empty-mini {
  color: #64748b;
  font-size: 12px;
  font-style: italic;
}

.link-btn {
  border: none;
  background: transparent;
  color: #60a5fa;
  font-size: 12px;
  font-weight: 800;
  cursor: pointer;

  &:hover {
    color: #93c5fd;
  }
}

@container main-panel (max-width: 430px) {
  .ministry-modal {
    width: 95vw;
    max-height: 75vh;
  }
}

// ── 编辑模式表单 ──
.edit-field {
  display: flex;
  align-items: center;
  gap: 8px;
}

.form-select,
.form-input,
.form-textarea,
.form-num {
  padding: 4px 7px;
  border: 1px solid rgba(148, 163, 184, 0.25);
  border-radius: 3px;
  background: rgba(2, 6, 23, 0.6);
  color: #e2e8f0;
  font-size: 12px;
  outline: none;
  transition: border-color 0.15s ease;

  &:focus {
    border-color: #3b82f6;
  }
}

.form-select {
  min-width: 80px;
}

.form-input {
  width: 100%;
}

.form-textarea {
  width: 100%;
  resize: vertical;
  min-height: 56px;
  line-height: 1.45;
  font-family: inherit;
}

.form-num {
  width: 56px;
  text-align: center;
  font-weight: 800;
}
